-- Regular views (depend on tables above).
CREATE VIEW IF NOT EXISTS price_data.ohlc_15min_query AS SELECT asset_id, interval_start, argMinMerge(open_state) AS open, maxMerge(high_state) AS high, minMerge(low_state) AS low, argMaxMerge(close_state) AS close, sumMerge(volume_buy_state) AS volume_buy, sumMerge(volume_sell_state) AS volume_sell, sumMerge(volume_buy_state) + sumMerge(volume_sell_state) AS volume_total FROM price_data.ohlc_15min WHERE (asset_id = {asset_id:UInt32}) AND ((interval_start >= {start_time:DateTime}) AND (interval_start <= {end_time:DateTime})) GROUP BY asset_id, interval_start ORDER BY interval_start ASC;
