CREATE VIEW IF NOT EXISTS price_data.price_at_block AS SELECT asset_id, block_height, round(usd_price, 8) AS usd_price FROM price_data.prices FINAL WHERE (asset_id = {asset_id:UInt32}) AND (block_height = {block_height:UInt32});
CREATE VIEW IF NOT EXISTS price_data.price_at_block_by_symbol AS SELECT asset_id, block_height, round(usd_price, 8) AS usd_price FROM price_data.prices FINAL WHERE (asset_id = (SELECT asset_id FROM price_data.assets FINAL WHERE symbol = {symbol:String} LIMIT 1)) AND (block_height = {block_height:UInt32});
CREATE VIEW IF NOT EXISTS price_data.price_at_timestamp AS WITH nearest_block AS (SELECT argMin(block_height, abs(toUnixTimestamp(block_timestamp) - toUnixTimestamp({target_timestamp:DateTime}))) AS block_height FROM price_data.blocks WHERE (block_timestamp >= ({target_timestamp:DateTime} - toIntervalHour(1))) AND (block_timestamp <= ({target_timestamp:DateTime} + toIntervalHour(1)))) SELECT asset_id, block_height, round(usd_price, 8) AS usd_price FROM price_data.prices FINAL WHERE (asset_id = {asset_id:UInt32}) AND (block_height = (SELECT block_height FROM nearest_block));
CREATE VIEW IF NOT EXISTS price_data.price_range AS WITH base AS (SELECT block_height, round(usd_price, 8) AS usd_price FROM price_data.prices FINAL WHERE (asset_id = {asset_id:UInt32}) AND ((block_height >= {start_block:UInt32}) AND (block_height <= {end_block:UInt32}))) SELECT block_height, usd_price FROM base ORDER BY block_height ASC WITH FILL FROM {start_block:UInt32} TO {end_block:UInt32} + 1 STEP 1 INTERPOLATE (`usd_price` AS usd_price);
